module branch_predictor(  
    input clk,  
    input reset,  
    input taken,  
    output reg prediction  
);  
    reg [1:0] obf_counter;  

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            obf_counter <= 2'b00;  
        else begin  
            if (taken)  
                obf_counter <= (obf_counter == 2'b11) ? 2'b11 : obf_counter + 1;  
            else  
                obf_counter <= (obf_counter == 2'b00) ? 2'b00 : obf_counter - 1;  
        end  
    end  

    always @(*) begin  
        prediction = (obf_counter[1] == 1'b1);  
    end  
endmodule
